import { isString } from 'lodash-es';
import { type ReactNode } from 'react';

import type { SeriesActionsTemplate } from '../../../../types/series-actions-template.js';
import { EmojiShape } from '../../../shape/EmojiShape/EmojiShape.js';
import { IconShape } from '../../../shape/IconShape/IconShape.js';
import { PrimaryAtom } from '../../../tooltip-atoms/components/PrimaryAtom.js';
import { TooltipInfoContent } from '../../section-components/TooltipInfoContent/TooltipInfoContent.js';
import { TooltipItem } from '../../section-components/TooltipItem/TooltipItem.js';
import { TooltipSymbolContent } from '../../section-components/TooltipSymbolContent/TooltipSymbolContent.js';
import { TooltipValueContent } from '../../section-components/TooltipValueContent/TooltipValueContent.js';

/**
 * Props of the KeyValue tooltip template
 * @internal
 */
export interface KeyValueProps {
  /** Icon element */
  icon: ReactNode;
  /** Primary Atom name */
  name: string;
  /** Value content */
  value: string;
  /** Series action */
  actions?: () => SeriesActionsTemplate;
}

/**
 *  @internal
 *  Tooltip template
 * */
export const KeyValue = ({ icon, name, value, actions }: KeyValueProps) => {
  return (
    <TooltipItem actions={actions}>
      <TooltipSymbolContent>
        {isString(icon) ? (
          <EmojiShape>{icon}</EmojiShape>
        ) : (
          <IconShape>{icon}</IconShape>
        )}
      </TooltipSymbolContent>
      <TooltipInfoContent>
        <PrimaryAtom>{name}</PrimaryAtom>
      </TooltipInfoContent>
      <TooltipValueContent>{value}</TooltipValueContent>
    </TooltipItem>
  );
};

KeyValue['displayName'] = 'ChartTooltip.KeyValue';
